select.trim:
AND c.del_flag = '0'
 and c.name like concat('%', #{name}, '%')
 and c.organizations like concat('%', #{organizations}, '%')
 and c.scope_type = #{scopeType}
 and c.status = #{status}




    AND (
    SELECT GROUP_CONCAT(cat ORDER BY cat SEPARATOR ',')
    FROM (
    SELECT SUBSTRING_INDEX(SUBSTRING_INDEX(c.category, ',', n), ',', -1) AS cat
    FROM (SELECT 1 n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4) numbers
    WHERE n <=  LENGTH(c.category) - LENGTH(REPLACE(c.category, ',', '')) + 1
    ) AS split_category
    ) = (
    SELECT GROUP_CONCAT(cat ORDER BY cat SEPARATOR ',')
    FROM (

        SELECT #{cat} AS cat

    ) AS temp
    )




    AND (
    SELECT GROUP_CONCAT(lev ORDER BY lev SEPARATOR ',')
    FROM (
    SELECT SUBSTRING_INDEX(SUBSTRING_INDEX(c.level, ',', n), ',', -1) AS lev
    FROM (SELECT 1 n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4) numbers
    WHERE n <=  LENGTH(c.level) - LENGTH(REPLACE(c.level, ',', '')) + 1
    ) AS split_level
    ) = (
    SELECT GROUP_CONCAT(lev ORDER BY lev SEPARATOR ',')
    FROM (

        SELECT #{lev} AS lev

    ) AS temp
    )




    AND (
    SELECT GROUP_CONCAT(tag ORDER BY tag SEPARATOR ',')
    FROM (
    SELECT SUBSTRING_INDEX(SUBSTRING_INDEX(c.tags, ',', n), ',', -1) AS tag
    FROM (SELECT 1 n UNION ALL SELECT 2 UNION ALL SELECT 3 UNION ALL SELECT 4) numbers
    WHERE n <=  LENGTH(c.tags) - LENGTH(REPLACE(c.tags, ',', '')) + 1
    ) AS split_tags
    ) = (
    SELECT GROUP_CONCAT(tag ORDER BY tag SEPARATOR ',')
    FROM (

        SELECT #{tag} AS tag

    ) AS temp
    )

