name = #{name}, category = #{category}, organizations = #{organizations}, level = #{level}, tags = #{tags}, scope_type = #{scopeType}, status = #{status}, memo = #{memo}, create_by = #{createBy}, create_time = #{createTime}, update_by = #{updateBy}, update_time = #{updateTime}, del_flag = #{delFlag},
